dark.customCSS:
/* --- SOLAR FLARE LUXURY UI --- */
* {
	border-color: rgba(255, 180, 50, 0.15) !important;
}

/* Golden Prose */
.prose h1, .prose h2, .prose h3 {
	color: #ffcc00 !important;
	text-shadow: 0 0 10px rgba(255, 204, 0, 0.3);
	font-weight: 800 !important;
}
.prose code {
	color: #ffaa00 !important;
	background-color: rgba(255, 170, 0, 0.1) !important;
	border: 1px solid rgba(255, 170, 0, 0.3);
}

/* Obsidian Frosted Inputs */
input, textarea, .bg-gray-850 {
	background-color: rgba(18, 9, 2, 0.6) !important;
	backdrop-filter: blur(10px) !important;
	-webkit-backdrop-filter: blur(10px) !important;
	border: 1px solid rgba(255, 180, 50, 0.2) !important;
	border-radius: 12px !important;
	transition: all 0.3s ease;
}
input:focus, textarea:focus {
	border-color: #ffcc00 !important;
	box-shadow: 0 0 15px rgba(255, 204, 0, 0.15) !important;
}

/* Sunflare Gradient Buttons */
button.bg-blue-500, button.bg-blue-600, .bg-black {
	background: linear-gradient(135deg, #ffcc00, #ff6600) !important;
	border: none !important;
	color: #26150a !important;
	font-weight: 700 !important;
	letter-spacing: 0.5px;
	box-shadow: 0 4px 15px rgba(255, 102, 0, 0.3);
	border-radius: 24px !important;
	transition: transform 0.2s cubic-bezier(0.34, 1.56, 0.64, 1);
}
button.bg-blue-500:hover, button.bg-blue-600:hover {
	transform: translateY(-2px) scale(1.03);
	box-shadow: 0 8px 25px rgba(255, 102, 0, 0.5) !important;
}

/* Molten Scrollbar */
::-webkit-scrollbar-thumb {
	background: #ffaa00 !important;
	border: 3px solid transparent;
	background-clip: content-box;
	border-radius: 10px;
}
::-webkit-scrollbar-track {
	background: transparent !important;
}

dark.canvasScript:
/**
 * Title: Solar Wind Embers
 * Description: Floating amber particles that drift upward and react to the sun (mouse).
 */

const CONFIG = {
    particleCount: 80,
    minSize: 1,
    maxSize: 4,
    baseColor: 'rgba(255, 180, 50, 0.2)',
    glowColor: 'rgba(255, 255, 200, 0.5)',
    driftSpeed: 0.4,
    mouseRadius: 200
};

let canvas, ctx, width, height;
let particles = [];
let mouse = { x: -5000, y: -5000 };

setInterval(() => self.postMessage({ type: 'heartbeat' }), 1000);

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas;
        ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    } else if (e.data.type === 'mousemove') {
        mouse.x = e.data.x;
        mouse.y = e.data.y;
    }
};

function resize(w, h) {
    width = w; height = h;
    if (canvas) { canvas.width = width; canvas.height = height; }
    initParticles();
}

function initParticles() {
    particles = [];
    for (let i = 0; i < CONFIG.particleCount; i++) {
        particles.push({
            x: Math.random() * width,
            y: Math.random() * height,
            vx: (Math.random() - 0.5) * 0.5,
            vy: -(Math.random() * CONFIG.driftSpeed + 0.2),
            size: Math.random() * (CONFIG.maxSize - CONFIG.minSize) + CONFIG.minSize,
            angle: Math.random() * Math.PI * 2
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, width, height);

    for (let p of particles) {
        p.y += p.vy;
        p.x += p.vx + Math.sin(p.angle) * 0.2;
        p.angle += 0.01;

        // Screen wrap
        if (p.y < -10) p.y = height + 10;
        if (p.x < -10) p.x = width + 10;
        if (p.x > width + 10) p.x = -10;

        // Mouse reaction
        let dx = mouse.x - p.x;
        let dy = mouse.y - p.y;
        let dist = Math.hypot(dx, dy);

        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);

        if (dist < CONFIG.mouseRadius) {
            ctx.fillStyle = CONFIG.glowColor;
            p.x -= dx * 0.01;
            p.y -= dy * 0.01;
        } else {
            ctx.fillStyle = CONFIG.baseColor;
        }

        ctx.fill();
    }

    requestAnimationFrame(render);
}

